                    ApplyOps = [RegOp.SetDword(RasKey, "VpnFilterAudit", 1)],
                    RemoveOps = [RegOp.DeleteValue(RasKey, "VpnFilterAudit")],
                    DetectOps = [RegOp.CheckDword(RasKey, "VpnFilterAudit", 1)],
