    private static class _CacheManagerPolicy
    {
        private const string Key = @"HKEY_LOCAL_MACHINE\SOFTWARE\Policies\Microsoft\Windows\CacheManager";

        internal static IReadOnlyList<TweakDef> Data { get; } =
