    // ── DnsSecurePolicy ──
    private static class _DnsSecurePolicy
    {
        private const string Key = @"HKEY_LOCAL_MACHINE\SOFTWARE\Policies\Microsoft\Windows\DNSClient";

        internal static IReadOnlyList<TweakDef> Data { get; } =
