    private static class _Ipv6Policy
    {
        private const string Key = @"HKEY_LOCAL_MACHINE\SOFTWARE\Policies\Microsoft\Windows\Tcpip\Parameters";

        internal static IReadOnlyList<TweakDef> Data { get; } =
