                RegistryKeys = [Key],
                ApplyOps = [RegOp.SetDword(Key, "DisableIPv6", 0xFF)],
                RemoveOps = [RegOp.DeleteValue(Key, "DisableIPv6")],
                DetectOps = [RegOp.CheckDword(Key, "DisableIPv6", 0xFF)],
