                    ApplyOps = [RegOp.SetDword(LdapPolicyKey, "UseLdapSsl", 1)],
                    RemoveOps = [RegOp.DeleteValue(LdapPolicyKey, "UseLdapSsl")],
                    DetectOps = [RegOp.CheckDword(LdapPolicyKey, "UseLdapSsl", 1)],
