                    ApplyOps = [RegOp.SetDword(LdapPolicyKey, "LdapDiagnosticsEnabled", 1)],
                    RemoveOps = [RegOp.DeleteValue(LdapPolicyKey, "LdapDiagnosticsEnabled")],
